using UnityEngine;
using UnityEngine.Purchasing;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats (Public)")]
    public int maxHealth = 100;
    public int health = 100;

    public int currency = 0;

    [Header("Combat (Public)")]
    public float baseDamage = 10f;
    public float damageMultiplier = 1f;
    public float critChance01 = 0.1f;
    public float critMultiplier = 2f;

    [Header("Progression (Public)")]
    public int damageLevel = 0;
    public int healthLevel = 0;

    [Header("Tuning (Public)")]
    public int damageUpgradeBasePrice = 50;
    public float damageUpgradePriceGrowth = 1.25f;
    public float damageUpgradePerLevel = 2f;

    public int healthUpgradeBasePrice = 40;
    public float healthUpgradePriceGrowth = 1.2f;
    public int healthUpgradePerLevel = 10;

    [Header("IAP Currency Packs (Public)")]
    public int iapSmallPackAmount = 100;
    public int iapMediumPackAmount = 500;
    public int iapLargePackAmount = 1200;

    public event Action OnStatsChanged;

    private System.Random rng;

    private void Awake()
    {
        rng = new System.Random(Guid.NewGuid().GetHashCode());
        ClampAndFix();
        RaiseChanged();
    }

    private void OnValidate()
    {
        ClampAndFix();
    }

    public void ClampAndFix()
    {
        if (maxHealth < 1) maxHealth = 1;
        if (health < 0) health = 0;
        if (health > maxHealth) health = maxHealth;

        if (currency < 0) currency = 0;

        if (baseDamage < 0f) baseDamage = 0f;
        if (damageMultiplier < 0f) damageMultiplier = 0f;

        critChance01 = Mathf.Clamp01(critChance01);
        if (critMultiplier < 1f) critMultiplier = 1f;

        if (damageLevel < 0) damageLevel = 0;
        if (healthLevel < 0) healthLevel = 0;

        if (damageUpgradeBasePrice < 0) damageUpgradeBasePrice = 0;
        if (damageUpgradePriceGrowth < 1f) damageUpgradePriceGrowth = 1f;
        if (damageUpgradePerLevel < 0f) damageUpgradePerLevel = 0f;

        if (healthUpgradeBasePrice < 0) healthUpgradeBasePrice = 0;
        if (healthUpgradePriceGrowth < 1f) healthUpgradePriceGrowth = 1f;
        if (healthUpgradePerLevel < 0) healthUpgradePerLevel = 0;

        if (iapSmallPackAmount < 0) iapSmallPackAmount = 0;
        if (iapMediumPackAmount < 0) iapMediumPackAmount = 0;
        if (iapLargePackAmount < 0) iapLargePackAmount = 0;
    }

    public int GetDamageUpgradePrice()
    {
        return CalcPrice(damageUpgradeBasePrice, damageUpgradePriceGrowth, damageLevel);
    }

    public int GetHealthUpgradePrice()
    {
        return CalcPrice(healthUpgradeBasePrice, healthUpgradePriceGrowth, healthLevel);
    }

    public float GetDamageNoCrit()
    {
        float dmg = baseDamage + (damageLevel * damageUpgradePerLevel);
        dmg *= damageMultiplier;
        return Mathf.Max(0f, dmg);
    }

    public float RollDamage(out bool crit)
    {
        float dmg = GetDamageNoCrit();
        crit = rng.NextDouble() < critChance01;
        if (crit) dmg *= critMultiplier;
        return Mathf.Max(0f, dmg);
    }

    public void TakeDamage(int amount)
    {
        if (amount <= 0) return;
        health = Mathf.Max(0, health - amount);
        RaiseChanged();
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        health = Mathf.Min(maxHealth, health + amount);
        RaiseChanged();
    }

    public void AddCurrency(int amount)
    {
        if (amount == 0) return;
        currency = Mathf.Max(0, currency + amount);
        RaiseChanged();
    }

    public bool SpendCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (currency < amount) return false;
        currency -= amount;
        RaiseChanged();
        return true;
    }

    public bool TryUpgradeDamage()
    {
        int price = GetDamageUpgradePrice();
        if (!SpendCurrency(price)) return false;
        damageLevel++;
        RaiseChanged();
        return true;
    }

    public bool TryUpgradeHealth()
    {
        int price = GetHealthUpgradePrice();
        if (!SpendCurrency(price)) return false;
        healthLevel++;
        maxHealth += healthUpgradePerLevel;
        health = Mathf.Min(health, maxHealth);
        RaiseChanged();
        return true;
    }

    private int CalcPrice(int basePrice, float growth, int level)
    {
        double p = basePrice * Math.Pow(growth, level);
        if (p < 0) p = 0;
        if (p > int.MaxValue) return int.MaxValue;
        return Mathf.Max(0, (int)Math.Ceiling(p));
    }

    private void RaiseChanged()
    {
        OnStatsChanged?.Invoke();
    }
}

public class Enemy : MonoBehaviour
{
    [Header("Enemy Stats (Public)")]
    public int maxHealth = 50;
    public int health = 50;

    [Header("Rewards (Public)")]
    public int currencyRewardOnDeath = 10;

    [Header("Damage Taken (Public)")]
    public float damageTakenMultiplier = 1f;

    public event Action<Enemy> OnDied;

    private void Awake()
    {
        if (maxHealth < 1) maxHealth = 1;
        health = Mathf.Clamp(health, 0, maxHealth);
        if (damageTakenMultiplier < 0f) damageTakenMultiplier = 0f;
        if (currencyRewardOnDeath < 0) currencyRewardOnDeath = 0;
    }

    public void ApplyDamage(float amount)
    {
        if (amount <= 0f) return;
        float final = amount * damageTakenMultiplier;
        int dmgInt = Mathf.Max(1, Mathf.FloorToInt(final));
        health = Mathf.Max(0, health - dmgInt);
        if (health == 0)
            Die();
    }

    private void Die()
    {
        OnDied?.Invoke(this);
        Destroy(gameObject);
    }
}

public class CombatController : MonoBehaviour
{
    public PlayerStats player;
    public Enemy targetEnemy;

    [Header("Combat Settings (Public)")]
    public bool autoAttack = false;
    public float attacksPerSecond = 2f;

    private float attackTimer;

    private void Update()
    {
        if (!autoAttack) return;
        if (player == null || targetEnemy == null) return;

        float interval = attacksPerSecond <= 0f ? 999999f : 1f / attacksPerSecond;
        attackTimer += Time.deltaTime;
        if (attackTimer >= interval)
        {
            attackTimer -= interval;
            AttackOnce();
        }
    }

    public void AttackOnce()
    {
        if (player == null || targetEnemy == null) return;
        bool crit;
        float dmg = player.RollDamage(out crit);
        targetEnemy.ApplyDamage(dmg);
    }

    public void SetTarget(Enemy enemy)
    {
        targetEnemy = enemy;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats player;

    [Header("Shop Items (Public)")]
    public int potionHealAmount = 25;
    public int potionBasePrice = 20;
    public float potionPriceGrowth = 1.1f;
    public int potionsBought = 0;

    public int flatCurrencyBonusAmount = 50;
    public int flatCurrencyBonusPrice = 60;

    public event Action OnShopChanged;

    private void OnValidate()
    {
        if (potionHealAmount < 0) potionHealAmount = 0;
        if (potionBasePrice < 0) potionBasePrice = 0;
        if (potionPriceGrowth < 1f) potionPriceGrowth = 1f;
        if (potionsBought < 0) potionsBought = 0;

        if (flatCurrencyBonusAmount < 0) flatCurrencyBonusAmount = 0;
        if (flatCurrencyBonusPrice < 0) flatCurrencyBonusPrice = 0;
    }

    public int GetPotionPrice()
    {
        double p = potionBasePrice * Math.Pow(potionPriceGrowth, potionsBought);
        if (p < 0) p = 0;
        if (p > int.MaxValue) return int.MaxValue;
        return Mathf.Max(0, (int)Math.Ceiling(p));
    }

    public bool BuyPotion()
    {
        if (player == null) return false;
        int price = GetPotionPrice();
        if (!player.SpendCurrency(price)) return false;

        potionsBought++;
        player.Heal(potionHealAmount);
        OnShopChanged?.Invoke();
        return true;
    }

    public bool BuyFlatCurrencyBonus()
    {
        if (player == null) return false;
        if (!player.SpendCurrency(flatCurrencyBonusPrice)) return false;
        player.AddCurrency(flatCurrencyBonusAmount);
        OnShopChanged?.Invoke();
        return true;
    }

    public bool BuyDamageUpgrade()
    {
        if (player == null) return false;
        bool ok = player.TryUpgradeDamage();
        if (ok) OnShopChanged?.Invoke();
        return ok;
    }

    public bool BuyHealthUpgrade()
    {
        if (player == null) return false;
        bool ok = player.TryUpgradeHealth();
        if (ok) OnShopChanged?.Invoke();
        return ok;
    }
}

public class IAPManager : MonoBehaviour, IStoreListener
{
    public PlayerStats player;

    [Header("Product IDs (Public)")]
    public string smallPackProductId = "coins_small";
    public string mediumPackProductId = "coins_medium";
    public string largePackProductId = "coins_large";

    private IStoreController storeController;
    private IExtensionProvider extensionProvider;

    public bool IsInitialized => storeController != null;

    private void Start()
    {
        InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (IsInitialized) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        builder.AddProduct(smallPackProductId, ProductType.Consumable);
        builder.AddProduct(mediumPackProductId, ProductType.Consumable);
        builder.AddProduct(largePackProductId, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuySmallPack() => BuyProductId(smallPackProductId);
    public void BuyMediumPack() => BuyProductId(mediumPackProductId);
    public void BuyLargePack() => BuyProductId(largePackProductId);

    public void RestorePurchases()
    {
#if UNITY_IOS
        if (!IsInitialized) return;
        var apple = extensionProvider.GetExtension<IAppleExtensions>();
        apple.RestoreTransactions(result => { });
#endif
    }

    private void BuyProductId(string productId)
    {
        if (!IsInitialized) return;

        Product product = storeController.products.WithID(productId);
        if (product != null && product.availableToPurchase)
            storeController.InitiatePurchase(product);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        storeController = controller;
        extensionProvider = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error)
    {
    }

#if UNITY_2022_2_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message)
    {
    }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs e)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        if (string.Equals(e.purchasedProduct.definition.id, smallPackProductId, StringComparison.Ordinal))
            player.AddCurrency(player.iapSmallPackAmount);
        else if (string.Equals(e.purchasedProduct.definition.id, mediumPackProductId, StringComparison.Ordinal))
            player.AddCurrency(player.iapMediumPackAmount);
        else if (string.Equals(e.purchasedProduct.definition.id, largePackProductId, StringComparison.Ordinal))
            player.AddCurrency(player.iapLargePackAmount);

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason)
    {
    }
}